export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:02。回到閱覽室。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上還是剛才那四套文件。藍色、灰色、米色、白色。佐伯把咖啡杯挪到桌角，杯底在紙面上留了一個淺色的圓印。他沒有擦。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "接下來比異常時間。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不要先想答案。各自抄。抄完再疊。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不先想答案。他在防確認偏誤。如果我們先說「找六點十三」，就會只看見六點十三。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把三份較完整的報告分開攤在桌上。葵的裝置報告。美空的醫療追蹤摘要。蓮的睡眠事件表。悠真的簡易結果畫面放在旁邊，但他先碰都沒碰。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳抄葵。我抄美空。蓮的我們一起看。悠真的最後再說。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪拿起葵的裝置報告。A4 影本，左上角有裝置型號，正文是表格。每一行是一個日期，旁邊標記當晚的睡眠事件類型。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從第一行開始。不是找特定時間。是抄出所有被系統標成「異常」的時間。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "03:47。覺醒短暫。04:22。體動異常。05:51。心跳變異偏低。06:13。覺醒／同步補正。06:55。再入睡。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把每一個標記異常的時間抄在空白紙上。不挑。不解釋。只抄。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯抄。像查核報告一樣。先列。後比。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯那邊也很快。美空的醫療追蹤摘要格式不同，欄位更密，但被標記的異常事件不多。他的字寫得小而整齊，像在填物流排班表。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人各自抄完。佐伯把蓮的睡眠事件表推到中間。兩個人一起看。蓮的表格最簡單，只有日期和事件描述，沒有裝置型號欄。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們把蓮的異常時間也抄出來。然後佐伯拿出一張新的空白紙。橫放。畫了三條直線，分成三欄。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "疊表。三欄。各自貼上去。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三份清單並排。左欄是葵。中欄是美空。右欄是蓮。每一個時間按順序從上到下排列。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯拿一支螢光筆。不畫。先看。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "找重複的分鐘。不是找重複的時間。是分鐘。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯分鐘。不是小時。不是秒。是分鐘。他知道分鐘層級的同步才是後台的行為。秒太細，可能是巧合。小時太粗，什麼都重複。分鐘——", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沿著三欄從上往下看。03:47 只出現在葵。04:22 只出現在葵。05:51 只出現在葵。05:38 出現在美空。05:44 出現在蓮。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "06:13。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "葵。06:13。覺醒／同步補正。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "美空。06:13。資料重新連線／事件。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "蓮。06:13。裝置事件／覺醒候補。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三欄。同一分鐘。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的手指停在紙面上。停在 06:13 那一行。指尖壓著紙。沒有移動。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯六點十三分。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯每一次。每一次回到星期一。手機震動。白光。六點十三分。我的身體記得那個時間。我的手指記得那個震動的間隔。我的肋骨記得醒來時那一下撞擊。六點十三分。不是六點十分。不是六點十五分。是六點十三分。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能說。不能告訴他。如果我說六點十三分是我的——他會問我怎麼知道。他會問我為什麼一個分鐘能讓我停下來。他會問我我在隱瞞什麼。我不能說。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手從紙面上移開。慢慢移開。像在收回一個不該被看見的動作。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "三份報告。唯一重複的分鐘。06:13。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得很平。像在讀一欄數字。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "如果後台一樣，這可能只是每天六點十三分做同步。不是三個孩子同時醒，是三套報表同時被寫了一筆。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那為什麼其中兩份把它翻成覺醒？", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見自己的聲音。穩的。沒有抖。她不知道怎麼做到的。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這才是能查的問題。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯放下螢光筆。手指交叉，撐在桌面上。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "是孩子醒了，還是系統把某件事翻譯成孩子醒了。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯翻譯。他用的是翻譯。不是記錄。不是偵測。是翻譯。系統把某一件事——某一個他還不知道是什麼的事——翻成了「覺醒」。翻成了孩子醒來。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上安靜了幾秒。閱覽室外面有人走過。腳步聲在走廊上拖了一下，消失。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "還有一件事。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "我們沒有普通參加者的報告。沒有不出事的。沒有非 G07 的。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "六點十三可能是 G07 的事。也可能是所有 TKS 裝置每天都會寫的一行。我們分不出來。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯對照組。他說的是對照組。沒有對照組，06:13 什麼都證明不了。對他而言。對文件而言。對任何一個正常人而言。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但我知道。我知道 06:13 不是所有裝置每天都會寫的一行。因為 06:13 是我醒來的時間。每一次。每一輪。六點十三分。我的手機。我的肋骨。我的天花板。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但我不能說。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著疊表上那三個 06:13。螢光筆還沒有畫下去。佐伯在等。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "書面結論。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "三份不同表面裝置的報告，在同一分鐘記錄相似類型的系統事件。它們很可能共用資料轉譯或同步層。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不能寫三個孩子在六點十三同時醒來。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拿起筆。在官方筆記上抄下佐伯的措辭。一個字一個字。像在抄一份查核結論。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她翻開私人筆記。在另一頁上寫了一行。不是結論。是一個問題。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）06:13——系統同步，還是別的什麼？", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有寫答案。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真的簡易結果畫面還在旁邊。佐伯拿起來看了一眼。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "悠真的只能看到 6:10 到 6:15 之間有尖峰。分鐘不精確。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "但 06:13 在範圍裡。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "在範圍裡不等於就是。記下來。6:10 到 6:15。尖峰。不能精確到分鐘。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯在範圍裡。06:13 在 6:10 到 6:15 之間。悠真的報告不夠精確。但 06:13 在那裡面。他的尖峰。我的錨點。同一個範圍。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把悠真的範圍也抄進官方筆記。旁邊標了來源：簡易結果畫面。分鐘不精確。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把螢光筆收進筆袋。疊表留在桌上。三個 06:13 並排。沒有被畫上螢光色。他選擇不畫。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不畫。畫了就像我們已經決定了。還沒決定。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯還沒決定。他不知道我已經決定了。我決定了 06:13 不是巧合。但我不能把這個決定放進他的文件裡。他的文件需要對照組。我的記憶不是對照組。我的記憶不能被查核。不能被複製。不能被別人看見。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:38。窗外的光又亮了一層。上午的太陽越過了對面公寓的屋頂，直接照進閱覽室。桌上的紙被曬得有點刺眼。佐伯把葵的裝置報告往陰影那邊挪了挪。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "休息五分鐘。下一項是 G07。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯G07。他說的是 G07。悠真的預約頁上寫的那個代碼。G07／12。今天早上在家庭餐廳填欄位時看見的。佐伯在旁邊寫了「意義未明」。我在私人筆記裡寫了「悠真」。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。去走廊的飲水機倒了一杯水。喝完。杯子放在窗台上。她看著走廊盡頭的出口指示燈。綠色。一直亮著。", background: Background.Chapter_12_Ch12_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯06:13。三個孩子。同一分鐘。同一個後台。我的錨點。他的同步。她的覺醒。他的事件。同一分鐘。我不能說。我只能把它和所有不能說的東西放在一起。千田的遺言。警方的倒數。06:13。三個不能說出口的東西。現在是四個了。", background: Background.Chapter_12_Ch12_Act4_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回到閱覽室。坐下。佐伯已經把美空的醫療追蹤 PDF 從米色資料夾裡抽出來了。", background: Background.Chapter_12_Ch12_Act4_S0 },
];
